#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>
#include <string.h>
int shared_val = 100;
int main(void) {
    setbuf(stdout, NULL);
    printf("Before fork: %d\n", shared_val);
    pid_t pid = fork();
    if (pid == 0) {
        printf("Child before write: %d\n", shared_val);
        shared_val = 999;
        printf("Child after write: %d\n", shared_val);
        _exit(0);
    }
    wait(&(int){0});
    printf("Parent after child exit: %d\n", shared_val);
    printf("COW works: %s\n", shared_val == 100 ? "yes" : "no");
    return 0;
}

