#include <string.h>

/* == EXEMPLE: fork + variable locale ================== */
void example_cow(void) {
    int x = 42;
    if (fork() == 0) { x = 0; printf("child x=%d\n", x); _exit(0); }
    wait(NULL);
    printf("parent x=%d\n", x);
}

